import zeep

# Set up the WSDL URL of the third-party service
wsdl_url = 'https://example.com/insurance_service?wsdl'

# Create a new Zeep client instance
client = zeep.Client(wsdl=wsdl_url)

def get_policy_details(policy_number, customer_name):
    # Create a SOAP request body with user-provided values
    policy_request = {
        'policyNumber': policy_number,
        'customerName': customer_name
    }

    # Convert the dictionary to a Zeep XML object
    xml_body = zeep.xsd.Element(
        client.get_element('ns:PolicyRequest', namespace='http://example.com/insurance_service'),
        policy_request
    )

    # Send the SOAP request and get the response
    try:
        response = client.service.get_policy_details(xml_body)
        return response
    except Exception as e:
        print(f"Error: {e}")
        return None

def main():
    # Get user input for policy lookup
    policy_number = input("Enter policy number: ")
    customer_name = input("Enter customer name: ")

    # Call the get_policy_details function with user-provided values
    response = get_policy_details(policy_number, customer_name)

    if response:
        print(response)
    else:
        print("Failed to retrieve policy details.")

if __name__ == "__main__":
    main()